final:
module RefModule (
    input [3:0] in,   // 4 input signals
    input [1:0] sel,  // 2 select lines
    output out        // output signal
);
    wire __sel_tmp = (sel == 2'b00);
    assign out = __sel_tmp ? in[0] : (sel == 2'b01) ? in[1] :
                 (sel == 2'b10) ? in[2] :
                 in[3]; // sel == 2'b11
endmodule
